{"path":"/tmp/isolated_workspace_1091/src/RiichiAdvanceCalculator.java","content":"import java.io.*;
import java.nio.charset.StandardCharsets;
import java.nio.file.*;
import java.util.*;
import java.util.regex.*;

public class RiichiAdvanceCalculator {
    static final int PLAYER_COUNT = 4;
    static final int TARGET_TOTAL_POINTS = 100000;
    static final int RIICHI_STICKS_VALUE = 1000;
    static final int HONBA_RON_BONUS = 300;
    static final int HONBA_TSUMO_BONUS_PER_PLAYER = 100;
    static final int NOTEN_PENALTY_TOTAL = 3000;

    enum Wind { EAST, SOUTH, WEST, NORTH }

    static class Player {
        String name;
        Wind seat;
        double startPt;
        int score;

        Player copy() {
            Player p = new Player();
            p.name = name;
            p.seat = seat;
            p.startPt = startPt;
            p.score = score;
            return p;
        }
    }

    static class GameState {
        Wind dealer;
        List<Wind> seatOrder;
        List<Player> players;
        int advanceTopN;
        RuleSet ruleSet;
        int riichiSticks;
        int honba;
    }

    static class RuleSet {
        String name;
        double[] rankBonus;
        double oka;
        boolean dealerTenpaiContinue;

        RuleSet(String name, double[] rankBonus, double oka, boolean dealerTenpaiContinue) {
            this.name = name;
            this.rankBonus = rankBonus;
            this.oka = oka;
            this.dealerTenpaiContinue = dealerTenpaiContinue;
        }

        double finalPoint(PlayerScore ps) {
            int rankIndex = ps.rank - 1;
            double scorePt = (ps.score - 30000) / 1000.0;
            double okaValue = rankIndex == 0 ? oka : 0.0;
            return ps.startPt + scorePt + rankBonus[rankIndex] + okaValue;
        }
    }

    static class PlayerScore {
        Player player;
        int score;
        int rank;
        double finalPt;
    }

    static class OutcomeEval {
        boolean qualifies;
        List<String> qualifiers;
        List<PlayerScore> standing;
    }

    static class TsumoResult {
        boolean dealerWin;
        int childPay;
        int dealerPay;
        String label() {
            if (dealerWin) return childPay + "all";
            return childPay + "・" + dealerPay;
        }
    }

    static class RonResult {
        int ronPoints;
        String label() { return String.valueOf(ronPoints); }
    }

    static class ThresholdResult {
        Integer min;
        Integer max;
        boolean exists;
        boolean all;

        static ThresholdResult none() { return new ThresholdResult(); }
        static ThresholdResult any() { ThresholdResult r = new ThresholdResult(); r.exists = true; r.all = true; return r; }
        String format(String suffix) {
            if (!exists) return "无";
            if (all) return "任意" + suffix;
            if (min != null && max != null && min.equals(max)) return min + suffix;
            if (min != null && max == null) return min + "以上" + suffix;
            if (min == null) return max + "以下" + suffix;
            return min + "~" + max + suffix;
        }
    }

    static class Candidate {
        String text;
        int sortValue;
        Candidate(String text, int sortValue) {
            this.text = text;
            this.sortValue = sortValue;
        }
    }

    public static void main(String[] args) throws Exception {
        String input;
        if (args.length >= 1) {
            input = Files.readString(Path.of(args[0]), StandardCharsets.UTF_8);
        } else {
            input = new String(System.in.readAllBytes(), StandardCharsets.UTF_8);
        }
        GameState state = parseInput(input);
        String report = buildReport(state);
        System.out.print(report);
    }

    static String buildReport(GameState state) {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < PLAYER_COUNT; i++) {
            Player actor = state.players.get(i);
            sb.append(actor.name).append("晋级条件\n");
            appendWinConditions(sb, state, i);
            sb.append("=============================\n");
            appendDealInConditions(sb, state, i);
            sb.append("=============================\n");
            appendTsumoTakenConditions(sb, state, i);
            sb.append("\n");
            sb.append(actor.name).append("危险区间:\n");
            appendDangerZones(sb, state, i);
            sb.append("\n");
        }
        sb.append("【流局16分支一览】\n");
        appendExhaustiveDrawTable(sb, state);
        return sb.toString();
    }

    static void appendWinConditions(StringBuilder sb, GameState state, int actorIdx) {
        Player actor = state.players.get(actorIdx);
        ThresholdResult tsumo = findTsumoWinThreshold(state, actorIdx);
        sb.append("自摸\t").append(formatTsumoThreshold(tsumo, actor.seat == state.dealer)).append("\n");
        sb.append("=============================\n");
        for (int from = 0; from < PLAYER_COUNT; from++) {
            if (from == actorIdx) continue;
            ThresholdResult ron = findRonWinThreshold(state, actorIdx, from);
            sb.append(state.players.get(from).name).append("荣和\t").append(ron.format("点"))
                    .append("\n");
        }
    }

    static void appendDealInConditions(StringBuilder sb, GameState state, int actorIdx) {
        for (int winner = 0; winner < PLAYER_COUNT; winner++) {
            if (winner == actorIdx) continue;
            ThresholdResult tr = findDealInSafeThreshold(state, actorIdx, winner);
            sb.append("对").append(state.players.get(winner).name).append("放铳\t")
                    .append(tr.format("点")).append("\n");
        }
    }

    static void appendTsumoTakenConditions(StringBuilder sb, GameState state, int actorIdx) {
        for (int winner = 0; winner < PLAYER_COUNT; winner++) {
            if (winner == actorIdx) continue;
            ThresholdResult tr = findHitByTsumoSafeThreshold(state, actorIdx, winner);
            String action = state.players.get(winner).seat == state.dealer ? "亲家自摸" : "自摸";
            sb.append("被").append(state.players.get(winner).name).append(action).append("\t")
                    .append(formatTsumoThreshold(tr, state.players.get(winner).seat == state.dealer)).append("\n");
        }
    }

    static void appendDangerZones(StringBuilder sb, GameState state, int actorIdx) {
        List<String> lines = new ArrayList<>();
        for (int winner = 0; winner < PLAYER_COUNT; winner++) {
            if (winner == actorIdx) continue;
            for (int loser = 0; loser < PLAYER_COUNT; loser++) {
                if (loser == actorIdx || loser == winner) continue;
                ThresholdResult tr = findDangerRonThreshold(state, actorIdx, winner, loser);
                if (tr.exists) {
                    lines.add(state.players.get(loser).name + "点" + state.players.get(winner).name + "\t" + tr.format("点会丢晋级资格"));
                }
            }
        }
        if (lines.isEmpty()) {
            sb.append("无\n");
        } else {
            for (String line : lines) sb.append(line).append("\n");
        }
    }

    static void appendExhaustiveDrawTable(StringBuilder sb, GameState state) {
        for (int mask = 0; mask < 16; mask++) {
            List<Integer> tenpai = new ArrayList<>();
            for (int i = 0; i < PLAYER_COUNT; i++) if (((mask >> i) & 1) == 1) tenpai.add(i);
            String label = describeTenpaiMask(state, tenpai);
            OutcomeEval eval = evaluateExhaustiveDraw(state, tenpai);
            sb.append(label).append("：[");
            for (int i = 0; i < eval.qualifiers.size(); i++) {
                if (i > 0) sb.append(", ");
                sb.append(eval.qualifiers.get(i));
            }
            sb.append("]晋级");
            if (state.ruleSet.dealerTenpaiContinue && tenpai.contains(indexOfDealer(state)) && indexOfDealer(state) == 3) {
                sb.append("，但").append(state.players.get(indexOfDealer(state)).name).append("听牌而继续");
            }
            sb.append("\n");
        }
    }

    static String describeTenpaiMask(GameState state, List<Integer> tenpai) {
        if (tenpai.size() == 0) return "全员未听牌";
        if (tenpai.size() == 4) return "全员听牌";
        if (tenpai.size() == 1) return state.players.get(tenpai.get(0)).name + "一人听牌";
        if (tenpai.size() == 3) {
            for (int i = 0; i < PLAYER_COUNT; i++) if (!tenpai.contains(i)) return state.players.get(i).name + "一人未听牌";
        }
        StringJoiner joiner = new StringJoiner("、");
        for (int idx : tenpai) joiner.add(state.players.get(idx).name);
        return joiner + "听牌";
    }

    static ThresholdResult findRonWinThreshold(GameState state, int winnerIdx, int loserIdx) {
        List<RonResult> cands = generateRonResults(state.honba);
        Integer min = null;
        for (RonResult r : cands) {
            OutcomeEval eval = evaluateRon(state, winnerIdx, loserIdx, r.ronPoints);
            if (eval.qualifies) {
                min = r.ronPoints;
                break;
            }
        }
        if (min == null) return ThresholdResult.none();
        ThresholdResult t = new ThresholdResult();
        t.exists = true;
        t.min = min;
        return t;
    }

    static ThresholdResult findTsumoWinThreshold(GameState state, int winnerIdx) {
        List<TsumoResult> cands = generateTsumoResults(state.honba);
        Integer minIndex = null;
        for (int i = 0; i < cands.size(); i++) {
            OutcomeEval eval = evaluateTsumo(state, winnerIdx, cands.get(i));
            if (eval.qualifies) {
                minIndex = i;
                break;
            }
        }
        if (minIndex == null) return ThresholdResult.none();
        ThresholdResult t = new ThresholdResult();
        t.exists = true;
        t.min = minIndex;
        return t;
    }

    static ThresholdResult findDealInSafeThreshold(GameState state, int actorIdx, int winnerIdx) {
        List<RonResult> cands = generateRonResults(state.honba);
        Integer maxSafe = null;
        boolean anySafe = false;
        for (RonResult r : cands) {
            OutcomeEval eval = evaluateRon(state, winnerIdx, actorIdx, r.ronPoints);
            if (playerQualifies(eval, actorIdx)) {
                anySafe = true;
                maxSafe = r.ronPoints;
            } else {
                break;
            }
        }
        if (!anySafe) return ThresholdResult.none();
        ThresholdResult t = new ThresholdResult();
        t.exists = true;
        t.max = maxSafe;
        return t;
    }

    static ThresholdResult findHitByTsumoSafeThreshold(GameState state, int actorIdx, int winnerIdx) {
        List<TsumoResult> cands = generateTsumoResults(state.honba);
        Integer maxSafeIndex = null;
        boolean anySafe = false;
        for (int i = 0; i < cands.size(); i++) {
            OutcomeEval eval = evaluateTsumo(state, winnerIdx, cands.get(i));
            if (playerQualifies(eval, actorIdx)) {
                anySafe = true;
                maxSafeIndex = i;
            } else {
                break;
            }
        }
        if (!anySafe) return ThresholdResult.none();
        ThresholdResult t = new ThresholdResult();
        t.exists = true;
        t.max = maxSafeIndex;
        return t;
    }

    static ThresholdResult findDangerRonThreshold(GameState state, int actorIdx, int winnerIdx, int loserIdx) {
        List<RonResult> cands = generateRonResults(state.honba);
        Integer minDanger = null;
        Integer maxDanger = null;
        for (RonResult r : cands) {
            OutcomeEval eval = evaluateRon(state, winnerIdx, loserIdx, r.ronPoints);
            if (!playerQualifies(eval, actorIdx)) {
                if (minDanger == null) minDanger = r.ronPoints;
                maxDanger = r.ronPoints;
            }
        }
        if (minDanger == null) return ThresholdResult.none();
        ThresholdResult t = new ThresholdResult();
        t.exists = true;
        t.min = minDanger;
        t.max = maxDanger;
        return t;
    }

    static String formatTsumoThreshold(ThresholdResult tr, boolean dealerWin) {
        if (!tr.exists) return "无";
        List<TsumoResult> cands = generateTsumoResults(0);
        if (tr.all) return "任意";
        if (tr.min != null && tr.max == null) return cands.get(tr.min).label() + "以上";
        if (tr.min == null && tr.max != null) return cands.get(tr.max).label() + "以下";
        return cands.get(tr.min).label() + "~" + cands.get(tr.max).label();
    }

    static boolean playerQualifies(OutcomeEval eval, int playerIdx) {
        String name = eval.standing.get(playerIdx).player.name;
        return eval.qualifiers.contains(name);
    }

    static OutcomeEval evaluateRon(GameState state, int winnerIdx, int loserIdx, int ronBasePoints) {
        int[] scores = currentScores(state);
        int gain = ronBasePoints + state.honba * HONBA_RON_BONUS + state.riichiSticks * RIICHI_STICKS_VALUE;
        int loss = ronBasePoints + state.honba * HONBA_RON_BONUS;
        scores[winnerIdx] += gain;
        scores[loserIdx] -= loss;
        return evaluateScores(state, scores);
    }

    static OutcomeEval evaluateTsumo(GameState state, int winnerIdx, TsumoResult tr) {
        int[] scores = currentScores(state);
        scores[winnerIdx] += state.riichiSticks * RIICHI_STICKS_VALUE;
        for (int i = 0; i < PLAYER_COUNT; i++) {
            if (i == winnerIdx) continue;
            int pay;
            if (tr.dealerWin) {
                pay = tr.childPay + state.honba * HONBA_TSUMO_BONUS_PER_PLAYER;
            } else {
                pay = (state.players.get(i).seat == state.dealer ? tr.dealerPay : tr.childPay) + state.honba * HONBA_TSUMO_BONUS_PER_PLAYER;
            }
            scores[i] -= pay;
            scores[winnerIdx] += pay;
        }
        return evaluateScores(state, scores);
    }

    static OutcomeEval evaluateExhaustiveDraw(GameState state, List<Integer> tenpai) {
        int[] scores = currentScores(state);
        if (!tenpai.isEmpty() && tenpai.size() < 4) {
            int pay = NOTEN_PENALTY_TOTAL / tenpai.size();
            int loss = NOTEN_PENALTY_TOTAL / (PLAYER_COUNT - tenpai.size());
            for (int i = 0; i < PLAYER_COUNT; i++) {
                if (tenpai.contains(i)) scores[i] += pay;
                else scores[i] -= loss;
            }
        }
        return evaluateScores(state, scores);
    }

    static OutcomeEval evaluateScores(GameState state, int[] scores) {
        List<PlayerScore> list = new ArrayList<>();
        for (int i = 0; i < PLAYER_COUNT; i++) {
            PlayerScore ps = new PlayerScore();
            ps.player = state.players.get(i);
            ps.score = scores[i];
            list.add(ps);
        }
        list.sort((a, b) -> {
            if (a.score != b.score) return Integer.compare(b.score, a.score);
            return Integer.compare(seatPriority(a.player.seat), seatPriority(b.player.seat));
        });
        for (int i = 0; i < list.size(); i++) list.get(i).rank = i + 1;
        for (PlayerScore ps : list) ps.finalPt = state.ruleSet.finalPoint(ps);
        list.sort((a, b) -> {
            int c = Double.compare(b.finalPt, a.finalPt);
            if (c != 0) return c;
            if (a.score != b.score) return Integer.compare(b.score, a.score);
            return Integer.compare(seatPriority(a.player.seat), seatPriority(b.player.seat));
        });

        List<String> qualifiers = new ArrayList<>();
        for (int i = 0; i < state.advanceTopN; i++) qualifiers.add(list.get(i).player.name);

        Map<String, PlayerScore> byName = new HashMap<>();
        for (int i = 0; i < list.size(); i++) byName.put(list.get(i).player.name, list.get(i));
        List<PlayerScore> indexed = new ArrayList<>();
        for (Player p : state.players) indexed.add(byName.get(p.name));

        OutcomeEval eval = new OutcomeEval();
        eval.qualifiers = qualifiers;
        eval.qualifies = false;
        eval.standing = indexed;
        return eval;
    }

    static int seatPriority(Wind wind) {
        return switch (wind) {
            case EAST -> 0;
            case SOUTH -> 1;
            case WEST -> 2;
            case NORTH -> 3;
        };
    }

    static int[] currentScores(GameState state) {
        int[] s = new int[PLAYER_COUNT];
        for (int i = 0; i < PLAYER_COUNT; i++) s[i] = state.players.get(i).score;
        return s;
    }

    static List<RonResult> generateRonResults(int honba) {
        int[] bases = {
                1000, 1300, 1600, 2000, 2600, 3200, 3900, 5200, 6400, 7700,
                8000, 9600, 12000, 11600, 18000, 12000, 24000, 16000, 32000,
                24000, 48000, 32000, 64000, 48000, 96000
        };
        Set<Integer> set = new TreeSet<>();
        for (int b : bases) set.add(b);
        List<RonResult> list = new ArrayList<>();
        for (int v : set) {
            RonResult r = new RonResult();
            r.ronPoints = v;
            list.add(r);
        }
        list.sort(Comparator.comparingInt(a -> a.ronPoints));
        return list;
    }

    static List<TsumoResult> generateTsumoResults(int honba) {
        int[][] nonDealer = {
                {300, 500}, {400, 700}, {500, 1000}, {700, 1300}, {800, 1600},
                {1000, 2000}, {1300, 2600}, {1600, 3200}, {2000, 3900}, {2000, 4000},
                {3000, 6000}, {4000, 8000}, {6000, 12000}, {8000, 16000}, {12000, 24000},
                {16000, 32000}
        };
        int[] dealer = {500, 700, 1000, 1300, 1600, 2000, 2600, 3200, 3900, 4000, 6000, 8000, 12000, 16000, 24000, 32000};
        List<TsumoResult> list = new ArrayList<>();
        for (int v : dealer) {
            TsumoResult t = new TsumoResult();
            t.dealerWin = true;
            t.childPay = v;
            t.dealerPay = v;
            list.add(t);
        }
        for (int[] pair : nonDealer) {
            TsumoResult t = new TsumoResult();
            t.dealerWin = false;
            t.childPay = pair[0];
            t.dealerPay = pair[1];
            list.add(t);
        }
        list.sort(Comparator.comparingInt(a -> a.dealerWin ? a.childPay * 3 : a.childPay * 2 + a.dealerPay));
        return list;
    }

    static int indexOfDealer(GameState state) {
        for (int i = 0; i < PLAYER_COUNT; i++) if (state.players.get(i).seat == state.dealer) return i;
        return -1;
    }

    static GameState parseInput(String input) {
        Map<String, String> map = new LinkedHashMap<>();
        for (String raw : input.split("\\R")) {
            String line = raw.trim();
            if (line.isEmpty()) continue;
            String normalized = line.replace('：', ':');
            int idx = normalized.indexOf(':');
            if (idx < 0) continue;
            String key = normalized.substring(0, idx).trim();
            String value = normalized.substring(idx + 1).trim();
            map.put(key, value);
        }

        GameState state = new GameState();
        state.dealer = parseWind(requireAny(map, "当前亲家"));
        String seats = requireAny(map, "座次");
        String[] seatArr = seats.split("\\s+");
        state.seatOrder = new ArrayList<>();
        for (String s : seatArr) if (!s.isBlank()) state.seatOrder.add(parseWind(s));
        String[] names = requireAny(map, "名字").split("\\s+");
        double[] startPts = parseDoubleArray(requireAny(map, "开始前总分"));
        int[] scores = parseIntArray(requireAny(map, "当前分数"));
        state.advanceTopN = Integer.parseInt(requireAny(map, "晋级条件").trim());
        state.ruleSet = parseRuleSet(requireAny(map, "规则"));
        state.riichiSticks = Integer.parseInt(requireAny(map, "供托").trim());
        state.honba = Integer.parseInt(requireAny(map, "本场").trim());
        state.players = new ArrayList<>();
        for (int i = 0; i < PLAYER_COUNT; i++) {
            Player p = new Player();
            p.name = names[i];
            p.seat = state.seatOrder.get(i);
            p.startPt = startPts[i];
            p.score = scores[i];
            state.players.add(p);
        }
        return state;
    }

    static RuleSet parseRuleSet(String raw) {
        String s = raw.trim().toLowerCase(Locale.ROOT);
        if (s.contains("m") && s.contains("league")) return new RuleSet("M-League", new double[]{50, 10, -10, -30}, 0, true);
        if (s.equals("a") || s.contains("a规")) return new RuleSet("A规", new double[]{30, 10, -10, -30}, 0, true);
        if (s.contains("wrc")) return new RuleSet("WRC", new double[]{15, 5, -5, -15}, 0, true);
        if (s.contains("最高位")) return new RuleSet("最高位规", new double[]{30, 10, -10, -30}, 0, true);
        throw new IllegalArgumentException("不支持的规则: " + raw);
    }

    static Wind parseWind(String s) {
        return switch (s.trim()) {
            case "东" -> Wind.EAST;
            case "南" -> Wind.SOUTH;
            case "西" -> Wind.WEST;
            case "北" -> Wind.NORTH;
            default -> throw new IllegalArgumentException("无法识别风位: " + s);
        };
    }

    static String requireAny(Map<String, String> map, String key) {
        if (!map.containsKey(key)) throw new IllegalArgumentException("缺少字段: " + key);
        return map.get(key);
    }

    static double[] parseDoubleArray(String s) {
        String[] arr = s.trim().split("\\s+");
        double[] v = new double[arr.length];
        for (int i = 0; i < arr.length; i++) v[i] = Double.parseDouble(arr[i]);
        return v;
    }

    static int[] parseIntArray(String s) {
        String[] arr = s.trim().split("\\s+");
        int[] v = new int[arr.length];
        for (int i = 0; i < arr.length; i++) v[i] = Integer.parseInt(arr[i]);
        return v;
    }
}
"}

